  qq({ setId: "s003", type: "okuri", n: 3, category: WRITE, level: "送り仮名", unit: "送り仮名", questionType: "write", question: "正しい送り仮名で書きなさい。\n\nあきらか", answer: "明らか", note: "『明か』ではなく『明らか』。", targets: ["明", "明らか"] }),
  qq({ setId: "s003", type: "error", n: 1, category: WRITE, level: "誤字訂正", unit: "誤字訂正", questionType: "write", question: "まちがっている漢字を正しく直しなさい。\n\n問題の節明を読む。", answer: "説明", note: "『節明』ではなく『説明』。", targets: ["説", "明", "説明", "節明"] }),
  qq({ setId: "s003", type: "error", n: 2, category: WRITE, level: "誤字訂正", unit: "誤字訂正", questionType: "write", question: "まちがっている漢字を正しく直しなさい。\n\n植物を感察する。", answer: "観察", note: "『感察』ではなく『観察』。", targets: ["観", "察", "観察", "感察"] }),
  qq({ setId: "s003", type: "error", n: 3, category: WRITE, level: "誤字訂正", unit: "誤字訂正", questionType: "write", question: "まちがっている漢字を正しく直しなさい。\n\n参加の条見を確認する。", answer: "条件", note: "『条見』ではなく『条件』。", targets: ["条", "件", "条件", "条見"] })

